import { configuracionesEncryptDecrypt } from './config/encrypt.js'
import { customApis } from './config/endpoints.js'

/**
 * @deprecated Usar createApoloClient().decrypt()
 */
export const requestDesencryptCustomApi = async (dato, xrmContext) => {
  try {
    const url = xrmContext.Utility.getGlobalContext().getClientUrl()
    const parameters = {
      EncryptDescryptApi_In_rfsc_text_to_Desencrypt: dato,
      EncryptDescryptApi_In_key: configuracionesEncryptDecrypt.AESGCM,
    }
    const response = await fetch(`${url}/api/data/v9.2/${customApis.DesencriptarDatos}`, {
      method: 'POST',
      headers: {
        'OData-MaxVersion': '4.0',
        'OData-Version': '4.0',
        'Content-Type': 'application/json; charset=utf-8',
        Accept: 'application/json',
      },
      body: JSON.stringify(parameters),
    })
    const data = await response.json()
    return data.EncryptDescryptApi_Out_rfsc_text_to_Desencrypt
  } catch {
    return ''
  }
}
